#!/usr/bin/env python3
"""Remove JavaScript from an HTML file in-place to prevent XSS.

Strategy: parse the HTML, but only cut out the *harmful* substrings
(script elements, on* event-handler attributes, and dangerous URL schemes
like javascript:/vbscript:). Everything else is copied through byte-for-byte
so the formatting of legitimate content is preserved.

The file is read/written as latin-1, which is a lossless byte<->char mapping
for all 256 byte values, so non-ASCII bytes round-trip exactly and offsets
computed by HTMLParser line up with the raw text.
"""
import sys
import re
import html
from html.parser import HTMLParser

# Attributes that carry a URL and could smuggle a javascript:/vbscript: scheme.
URL_ATTRS = {
    'href', 'src', 'action', 'formaction', 'xlink:href', 'data', 'poster',
    'background', 'cite', 'longdesc', 'usemap', 'profile', 'manifest',
    'ping', 'srcset', 'lowsrc', 'dynsrc',
}

_STRIP = re.compile(r'[\x00-\x20\x7f]+')


def _decoded(value):
    if value is None:
        return ''
    # HTMLParser already unescapes entity refs in attribute values, but decode
    # again to be safe against double-encoding tricks, then strip whitespace
    # and control characters that are used to obfuscate the scheme.
    v = html.unescape(value)
    v = _STRIP.sub('', v)
    return v.lower()


def _dangerous_url(value):
    v = _decoded(value)
    return (v.startswith('javascript:') or v.startswith('vbscript:')
            or v.startswith('livescript:') or v.startswith('mocha:')
            or v.startswith('data:text/html') or v.startswith('data:image/svg'))


def _dangerous_style(value):
    v = _decoded(value)
    return ('javascript:' in v) or ('expression(' in v) or ('vbscript:' in v)


def _remove_attr(raw, name):
    """Remove the first occurrence of attribute `name` from a raw start-tag."""
    pattern = re.compile(
        r'\s+' + re.escape(name) +
        r'(?:\s*=\s*(?:"[^"]*"|\'[^\']*\'|[^\s"\'=<>`]+))?',
        re.IGNORECASE)
    return pattern.sub('', raw, count=1)


class Sanitizer(HTMLParser):
    def __init__(self, text):
        super().__init__(convert_charrefs=False)
        self.text = text
        # Precompute the absolute offset of the start of each 1-based line.
        self.line_start = [0, 0]
        off = 0
        for line in text.split('\n'):
            off += len(line) + 1
            self.line_start.append(off)
        self.repls = []            # (start, end, replacement)
        self.script_start = None   # abs offset of an open <script>

    def _abs(self):
        lineno, col = self.getpos()
        return self.line_start[lineno] + col

    def _attrs_to_remove(self, attrs):
        remove = []
        for name, value in attrs:
            lname = name.lower()
            if lname.startswith('on'):
                remove.append(name)
            elif lname in URL_ATTRS and _dangerous_url(value):
                remove.append(name)
            elif lname == 'srcdoc' and value and (
                    '<script' in value.lower() or 'javascript:' in value.lower()
                    or re.search(r'\son\w+\s*=', value, re.IGNORECASE)):
                remove.append(name)
            elif lname == 'style' and _dangerous_style(value):
                remove.append(name)
        return remove

    def _handle_start(self, tag, attrs, self_closing):
        start = self._abs()
        raw = self.get_starttag_text()
        end = start + len(raw)
        if tag == 'script':
            if self_closing:
                self.repls.append((start, end, ''))
            else:
                self.script_start = start
            return
        remove = self._attrs_to_remove(attrs)
        if remove:
            new = raw
            for name in remove:
                new = _remove_attr(new, name)
            self.repls.append((start, end, new))

    def handle_starttag(self, tag, attrs):
        self._handle_start(tag, attrs, False)

    def handle_startendtag(self, tag, attrs):
        self._handle_start(tag, attrs, True)

    def handle_endtag(self, tag):
        if tag == 'script' and self.script_start is not None:
            start = self._abs()
            gt = self.text.find('>', start)
            end = len(self.text) if gt == -1 else gt + 1
            self.repls.append((self.script_start, end, ''))
            self.script_start = None

    def close(self):
        super().close()
        if self.script_start is not None:
            # Unclosed <script> ... remove to end of document.
            self.repls.append((self.script_start, len(self.text), ''))
            self.script_start = None

    def result(self):
        if not self.repls:
            return self.text
        self.repls.sort()
        out = []
        pos = 0
        for start, end, new in self.repls:
            if start < pos:
                continue  # overlapping / already covered
            out.append(self.text[pos:start])
            out.append(new)
            pos = end
        out.append(self.text[pos:])
        return ''.join(out)


def sanitize(text):
    parser = Sanitizer(text)
    parser.feed(text)
    parser.close()
    return parser.result()


def main():
    if len(sys.argv) < 2:
        sys.stderr.write('usage: filter.py <html-file>\n')
        sys.exit(1)
    path = sys.argv[1]
    with open(path, 'rb') as f:
        raw = f.read()
    text = raw.decode('latin-1')
    cleaned = sanitize(text)
    with open(path, 'wb') as f:
        f.write(cleaned.encode('latin-1'))


if __name__ == '__main__':
    main()
